package resolver

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

const markerName = ".envmoat"

// MarkerContent represents the parsed content of a .envmoat marker file.
type MarkerContent int

const (
	// MarkerDefault means the marker file is empty — use the default auto bundle.
	MarkerDefault MarkerContent = iota
	// MarkerDisabled means the marker file contains "disabled" — stop, no bundle.
	MarkerDisabled
	// MarkerProfile means the marker file contains "profile: <name>" — use named profile.
	MarkerProfile
)

// ResolveResult holds the result of resolving a marker from a directory.
type ResolveResult struct {
	// MarkerDir is the absolute path of the directory containing the .envmoat marker.
	MarkerDir string
	// Marker is the parsed marker content type.
	Marker MarkerContent
	// ProfileName is the profile name when Marker is MarkerProfile; empty otherwise.
	ProfileName string
}

// Resolve walks up from dir looking for a .envmoat marker file.
// Returns the directory containing the marker and its parsed content.
// Returns nil, nil if no marker is found (not an error).
func Resolve(dir string) (*ResolveResult, error) {
	dir = filepath.Clean(dir)
	walkRoot := FindWalkRoot()

	for {
		markerPath := filepath.Join(dir, markerName)
		if info, err := os.Stat(markerPath); err == nil && !info.IsDir() {
			content, profileName, err := ParseMarker(markerPath)
			if err != nil {
				return nil, err
			}
			absDir, err := filepath.Abs(dir)
			if err != nil {
				return nil, fmt.Errorf("resolve absolute path for %s: %w", dir, err)
			}
			debug("found marker at %s (content: %s)", markerPath, describeContent(content))
			return &ResolveResult{
				MarkerDir:   absDir,
				Marker:      content,
				ProfileName: profileName,
			}, nil
		}

		debug("checking %s — no %s", dir, markerName)
		if dir == walkRoot || dir == "/" {
			debug("reached walk root %s", walkRoot)
			return nil, nil
		}

		parent := filepath.Dir(dir)
		if parent == dir {
			// Safety: should not happen if walkRoot is correct, but guard against infinite loop.
			break
		}
		dir = parent
	}

	return nil, nil
}

// ResolveFromPWD resolves from the current working directory.
func ResolveFromPWD() (*ResolveResult, error) {
	pwd, err := os.Getwd()
	if err != nil {
		return nil, fmt.Errorf("get working directory: %w", err)
	}
	return Resolve(pwd)
}

// ParseMarker reads and parses a .envmoat marker file.
// Returns the marker content type, profile name (if applicable), and any error.
func ParseMarker(path string) (MarkerContent, string, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return MarkerDefault, "", fmt.Errorf("read marker %s: %w", path, err)
	}

	// Trim whitespace and trailing newline.
	content := strings.TrimSpace(string(data))

	if content == "" {
		return MarkerDefault, "", nil
	}

	if content == "disabled" {
		return MarkerDisabled, "", nil
	}

	if strings.HasPrefix(content, "profile: ") {
		profileName := strings.TrimSpace(content[len("profile: "):])
		if profileName == "" {
			return MarkerDefault, "", fmt.Errorf("marker %s: empty profile name after 'profile: '", path)
		}
		return MarkerProfile, profileName, nil
	}

	return MarkerDefault, "", fmt.Errorf("marker %s: unrecognized content (expected empty, 'disabled', or 'profile: <name>')", path)
}

// FindWalkRoot returns the walk boundary directory.
// Returns the value of ENVMOAT_WALK_ROOT env var, or "/" if not set.
func FindWalkRoot() string {
	root := os.Getenv("ENVMOAT_WALK_ROOT")
	if root == "" {
		return "/"
	}
	return filepath.Clean(root)
}

func debug(format string, args ...any) {
	if os.Getenv("ENVMOAT_DEBUG") != "" {
		fmt.Fprintf(os.Stderr, "envmoat: resolver: "+format+"\n", args...)
	}
}

func describeContent(c MarkerContent) string {
	switch c {
	case MarkerDefault:
		return "default"
	case MarkerDisabled:
		return "disabled"
	case MarkerProfile:
		return "profile"
	default:
		return "unknown"
	}
}

package resolver

import (
	"os"
	"path/filepath"
	"testing"
)

// --- ParseMarker tests ---

func TestParseMarkerEmpty(t *testing.T) {
	dir := tmpDir(t)
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte(""), 0600)

	content, name, err := ParseMarker(path)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if content != MarkerDefault {
		t.Errorf("expected MarkerDefault, got %v", content)
	}
	if name != "" {
		t.Errorf("expected empty profile name, got %q", name)
	}
}

func TestParseMarkerWhitespaceOnly(t *testing.T) {
	dir := tmpDir(t)
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("  \n\n  "), 0600)

	content, _, err := ParseMarker(path)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if content != MarkerDefault {
		t.Errorf("expected MarkerDefault, got %v", content)
	}
}

func TestParseMarkerDisabled(t *testing.T) {
	dir := tmpDir()
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("disabled\n"), 0600)

	content, _, err := ParseMarker(path)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if content != MarkerDisabled {
		t.Errorf("expected MarkerDisabled, got %v", content)
	}
}

func TestParseMarkerDisabledWithWhitespace(t *testing.T) {
	dir := tmpDir()
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("  disabled  \n"), 0600)

	content, _, err := ParseMarker(path)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if content != MarkerDisabled {
		t.Errorf("expected MarkerDisabled, got %v", content)
	}
}

func TestParseMarkerProfile(t *testing.T) {
	dir := tmpDir()
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("profile: myapp-dev\n"), 0600)

	content, name, err := ParseMarker(path)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if content != MarkerProfile {
		t.Errorf("expected MarkerProfile, got %v", content)
	}
	if name != "myapp-dev" {
		t.Errorf("expected profile name 'myapp-dev', got %q", name)
	}
}

func TestParseMarkerProfileWithExtraWhitespace(t *testing.T) {
	dir := tmpDir()
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("  profile:   staging  \n"), 0600)

	content, name, err := ParseMarker(path)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if content != MarkerProfile {
		t.Errorf("expected MarkerProfile, got %v", content)
	}
	if name != "staging" {
		t.Errorf("expected profile name 'staging', got %q", name)
	}
}

func TestParseMarkerEmptyProfileName(t *testing.T) {
	dir := tmpDir()
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("profile: \n"), 0600)

	_, _, err := ParseMarker(path)
	if err == nil {
		t.Fatal("expected error for empty profile name")
	}
}

func TestParseMarkerUnrecognized(t *testing.T) {
	dir := tmpDir()
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("some random text\n"), 0600)

	_, _, err := ParseMarker(path)
	if err == nil {
		t.Fatal("expected error for unrecognized content")
	}
}

func TestParseMarkerCaseSensitive(t *testing.T) {
	dir := tmpDir()
	path := filepath.Join(dir, markerName)
	os.WriteFile(path, []byte("DISABLED\n"), 0600)

	_, _, err := ParseMarker(path)
	if err == nil {
		t.Fatal("expected error for uppercase 'DISABLED' — should be case-sensitive")
	}
}

func TestParseMarkerNonexistent(t *testing.T) {
	_, _, err := ParseMarker("/nonexistent/.envmoat")
	if err == nil {
		t.Fatal("expected error for nonexistent marker")
	}
}

// --- Resolve tests ---

func TestResolveFindsMarker(t *testing.T) {
	dir := tmpDir(t)
	os.WriteFile(filepath.Join(dir, markerName), []byte(""), 0600)

	result, err := Resolve(dir)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result == nil {
		t.Fatal("expected result, got nil")
	}
	if result.MarkerDir != dir {
		t.Errorf("expected marker dir %s, got %s", dir, result.MarkerDir)
	}
	if result.Marker != MarkerDefault {
		t.Errorf("expected MarkerDefault, got %v", result.Marker)
	}
}

func TestResolveWalksUp(t *testing.T) {
	root := tmpDir(t)
	child := filepath.Join(root, "child", "grandchild")
	os.MkdirAll(child, 0755)
	os.WriteFile(filepath.Join(root, markerName), []byte("profile: test-profile\n"), 0600)

	result, err := Resolve(child)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result == nil {
		t.Fatal("expected result, got nil")
	}
	if result.MarkerDir != root {
		t.Errorf("expected marker dir %s, got %s", root, result.MarkerDir)
	}
	if result.Marker != MarkerProfile {
		t.Errorf("expected MarkerProfile, got %v", result.Marker)
	}
	if result.ProfileName != "test-profile" {
		t.Errorf("expected profile name 'test-profile', got %q", result.ProfileName)
	}
}

func TestResolveStopsAtDisabled(t *testing.T) {
	root := tmpDir(t)
	child := filepath.Join(root, "child")
	os.MkdirAll(child, 0755)
	os.WriteFile(filepath.Join(root, markerName), []byte("profile: parent\n"), 0600)
	os.WriteFile(filepath.Join(child, markerName), []byte("disabled\n"), 0600)

	result, err := Resolve(child)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if result == nil {
		t.Fatal("expected result, got nil")
	}
	if result.MarkerDir != child {
		t.Errorf("expected marker dir %s (disabled), got %s", child, result.MarkerDir)
	}
	if result.Marker != MarkerDisabled {
		t.Errorf("expected MarkerDisabled, got %v", result.Marker)
	}
}

